1	// app/src/domain/adjudication/adjudicator.ts — the pure adjudication core.
2	// adjudicateLine(input) -> decision + accumulator deltas. No I/O: it reads a snapshot
3	// and returns the deltas for the caller to persist, which is what makes it deterministic
4	// and unit-testable with plain objects (no DB for the pure cycles).
5	
6	import type { LineItem, LineItemStatus } from "../entities/line-item";
7	import type { Policy } from "../entities/policy";
8	import { formatUsd } from "../money/cents";
9	import { ReasonCode } from "../reason-codes";
10	import type { CoverageRule } from "../rules/coverage-rule";
11	
12	export type AccumulatorSnapshot = {
13	  deductibleMetCents: number;
14	  oopMetCents: number;
15	  limitUsed: number; // cents for a dollar limit, a count for a visit limit
16	};
17	
18	export type AdjudicateLineInput = {
19	  line: LineItem;
20	  policy: Policy;
21	  rule: CoverageRule | undefined; // matched by serviceCode; undefined => NO_COVERAGE
22	  serviceDate: string; // claim-level ISO date (policy-active check)
23	  acc: AccumulatorSnapshot; // read-only snapshot taken at claim start
24	  alreadyAdjudicated: boolean; // true => DUPLICATE_LINE_ITEM
25	};
26	
27	export type AdjudicateLineResult = {
28	  status: LineItemStatus; // APPROVED | DENIED (NEEDS_REVIEW only via dispute)
29	  payableCents: number; // plan pays
30	  memberResponsibilityCents: number; // member owes
31	  reasons: ReasonCode[]; // dominant code first, then any breakdown
32	  explanation: string; // EOB sentence citing the rule + the numbers used
33	  deltas: { deductibleIncCents: number; oopIncCents: number; limitInc: number };
34	};
35	
36	export function adjudicateLine(
37	  input: AdjudicateLineInput,
38	): AdjudicateLineResult {
39	  const { rule, line, policy, serviceDate, acc, alreadyAdjudicated } = input;
40	
41	  // Every gate denial shares one shape: plan pays nothing, member owes nothing here
42	  // (a non-covered service is billed to the member directly, not as cost-share), and
43	  // no accumulator is touched. A denial is a processed decision, never an error.
44	  const deny = (
45	    reason: ReasonCode,
46	    explanation: string,
47	  ): AdjudicateLineResult => ({
48	    status: "DENIED",
49	    payableCents: 0,
50	    memberResponsibilityCents: 0,
51	    reasons: [reason],
52	    explanation,
53	    deltas: { deductibleIncCents: 0, oopIncCents: 0, limitInc: 0 },
54	  });
55	
56	  // GATES — fire in pipeline order; the first failing gate denies the line.
57	
58	  // Cycle 7 — duplicate fingerprint already adjudicated.
59	  if (alreadyAdjudicated) {
60	    return deny(
61	      ReasonCode.DUPLICATE_LINE_ITEM,
62	      `Duplicate line: ${line.serviceCode} was already adjudicated; the plan pays ${formatUsd(0)}.`,
63	    );
64	  }
65	
66	  // Cycle 5 — service date outside the policy's active window. ISO dates compare lexically.
67	  if (
68	    serviceDate < policy.effectiveDate ||
69	    serviceDate > policy.terminationDate
70	  ) {
71	    return deny(
72	      ReasonCode.POLICY_NOT_ACTIVE,
73	      `Policy not active: ${serviceDate} is outside the coverage window (${policy.effectiveDate}–${policy.terminationDate}); the plan pays ${formatUsd(0)}.`,
74	    );
75	  }
76	
77	  // Cycle 2 — no benefit rule matched this service_code.
78	  if (!rule) {
79	    return deny(
80	      ReasonCode.NO_COVERAGE,
81	      `No coverage: no benefit rule applies to ${line.serviceCode}, so the plan pays ${formatUsd(0)}.`,
82	    );
83	  }
84	
85	  // Cycle 3 — the rule explicitly excludes this service.
86	  if (rule.excluded) {
87	    return deny(
88	      ReasonCode.EXCLUDED,
89	      `Excluded benefit: ${line.serviceCode} is excluded from the plan, so the plan pays ${formatUsd(0)}.`,
90	    );
91	  }
92	
93	  // Cycle 4 — the rule exists but the service is not a covered benefit.
94	  if (!rule.covered) {
95	    return deny(
96	      ReasonCode.NO_COVERAGE,
97	      `No coverage: ${line.serviceCode} is not a covered benefit, so the plan pays ${formatUsd(0)}.`,
98	    );
99	  }
100	
101	  // Cycle 6 — prior auth required but not present → clean deny.
102	  if (rule.requiresPriorAuth && !line.priorAuthPresent) {
103	    return deny(
104	      ReasonCode.PRIOR_AUTH_REQUIRED,
105	      `Prior authorization required: ${line.serviceCode} needs prior auth, which was not present; the plan pays ${formatUsd(0)}.`,
106	    );
107	  }
108	
109	  // Cycle 15 — visit limit fully consumed → whole-visit denial (no partial visit).
110	  if (rule.limit.unit === "visits" && acc.limitUsed >= rule.limit.count) {
111	    return deny(
112	      ReasonCode.LIMIT_EXCEEDED,
113	      `Limit exceeded: ${line.serviceCode} has used all ${rule.limit.count} covered visits this plan year; the plan pays ${formatUsd(0)}.`,
114	    );
115	  }
116	
117	  // Dollar limit fully exhausted (no remaining at all) → denial. A *partial* remaining is
118	  // handled after cost-share as a straddle (cycle 17), where the line stays APPROVED.
119	  if (
120	    rule.limit.unit === "dollars" &&
121	    acc.limitUsed >= rule.limit.amountCents
122	  ) {
123	    return deny(
124	      ReasonCode.LIMIT_EXCEEDED,
125	      `Limit exceeded: ${line.serviceCode} has reached its ${formatUsd(rule.limit.amountCents)} annual limit; the plan pays ${formatUsd(0)}.`,
126	    );
127	  }
128	
129	  // ---- Cost-share (step 7): compute the base member / plan split. Every covered line
130	  // satisfies `payable + member === billed`. The limit step below may then shift money. ----
131	  let result: AdjudicateLineResult;
132	
133	  if (rule.costShare.type === "full_coverage") {
134	    // Cycle 1 — plan pays 100%, member owes nothing, deductible/OOP untouched.
135	    result = {
136	      status: "APPROVED",
137	      payableCents: line.billedCents,
138	      memberResponsibilityCents: 0,
139	      reasons: [ReasonCode.APPROVED],
140	      explanation: `Full coverage: the plan pays 100% (${formatUsd(line.billedCents)}); you owe ${formatUsd(0)}.`,
141	      deltas: { deductibleIncCents: 0, oopIncCents: 0, limitInc: 0 },
142	    };
143	  } else if (rule.costShare.type === "copay") {
144	    // Cycle 8–9 — flat copay; waives the deductible but counts to OOP; member ≤ allowed.
145	    const allowedCents = line.billedCents;
146	    const memberCents = Math.min(rule.costShare.copayCents, allowedCents);
147	    const planCents = allowedCents - memberCents;
148	    result = {
149	      status: "APPROVED",
150	      payableCents: planCents,
151	      memberResponsibilityCents: memberCents,
152	      reasons: [ReasonCode.APPROVED, ReasonCode.COPAY_APPLIED],
153	      explanation: `Copay: you pay the ${formatUsd(memberCents)} copay; the plan pays ${formatUsd(planCents)}.`,
154	      deltas: { deductibleIncCents: 0, oopIncCents: memberCents, limitInc: 0 },
155	    };
156	  } else {
157	    // Cycle 10–13 — coinsurance: the deductible draws first (when applies_deductible), then the
158	    // member pays `rate` of the remainder. Rounding lives only on the coinsurance share; `plan`
159	    // is computed last as `allowed − member`, so the shares always sum to allowed (no lost cent).
160	    const allowedCents = line.billedCents;
161	    const remainingDeductibleCents = Math.max(
162	      0,
163	      policy.deductibleCents - acc.deductibleMetCents,
164	    );
165	    const dedPortionCents = rule.appliesDeductible
166	      ? Math.min(remainingDeductibleCents, allowedCents)
167	      : 0;
168	    const remainderCents = allowedCents - dedPortionCents;
169	    const coinsPortionCents = Math.round(rule.costShare.rate * remainderCents); // half-up
170	    const memberCents = dedPortionCents + coinsPortionCents;
171	    const planCents = allowedCents - memberCents;
172	
173	    const reasons: ReasonCode[] = [ReasonCode.APPROVED];
174	    if (dedPortionCents > 0) reasons.push(ReasonCode.DEDUCTIBLE_APPLIED);
175	    reasons.push(ReasonCode.COINSURANCE_APPLIED);
176	
177	    const ratePct = Math.round(rule.costShare.rate * 100);
178	    const dedNote =
179	      dedPortionCents > 0
180	        ? `${formatUsd(dedPortionCents)} toward your deductible plus `
181	        : "";
182	    result = {
183	      status: "APPROVED",
184	      payableCents: planCents,
185	      memberResponsibilityCents: memberCents,
186	      reasons,
187	      explanation: `Coinsurance: you pay ${formatUsd(memberCents)} (${dedNote}${ratePct}% of ${formatUsd(remainderCents)}); the plan pays ${formatUsd(planCents)}.`,
188	      deltas: {
189	        deductibleIncCents: dedPortionCents,
190	        oopIncCents: memberCents,
191	        limitInc: 0,
192	      },
193	    };
194	  }
195	
196	  // ---- Limit application (steps 5b/7b/9): the gates above already denied a fully-exhausted
197	  // limit, so here there is room. A visit consumes one unit; a dollar limit accrues the plan
198	  // pay and may straddle the cap (cap plan at the remaining, shift the shortfall to member). ----
199	  if (rule.limit.unit === "visits") {
200	    // Cycle 14 — a covered visit consumes one unit of the visit allowance.
201	    result.deltas.limitInc = 1;
202	  } else if (rule.limit.unit === "dollars") {
203	    const remainingCents = rule.limit.amountCents - acc.limitUsed;
204	    if (result.payableCents > remainingCents) {
205	      // Cycle 17 — straddle: the plan pay crosses the remaining dollar cap. Cap the plan at
206	      // the remaining, push the shortfall to the member, note LIMIT_EXCEEDED; line stays
207	      // APPROVED. The over-limit shortfall is the member's own cost — it does not accrue to OOP.
208	      const shortfallCents = result.payableCents - remainingCents;
209	      result.payableCents = remainingCents;
210	      result.memberResponsibilityCents += shortfallCents;
211	      result.reasons = [...result.reasons, ReasonCode.LIMIT_EXCEEDED];
212	      result.deltas.limitInc = remainingCents;
213	      result.explanation += ` The ${formatUsd(rule.limit.amountCents)} annual limit is reached; ${formatUsd(shortfallCents)} is your responsibility.`;
214	    } else {
215	      // Cycle 16 — within the remaining dollar cap: the plan pay accrues to the limit.
216	      result.deltas.limitInc = result.payableCents;
217	    }
218	  }
219	
220	  // ---- OOP cap (step 8): the member never pays past the out-of-pocket maximum. If this
221	  // line's OOP-accruing share would cross the cap, refund the excess to the plan and fill the
222	  // OOP exactly to the max. The over-limit straddle shortfall is not OOP-eligible, so it is
223	  // never in deltas.oopIncCents and is correctly left out of this check. ----
224	  const oopRoomCents = policy.oopMaxCents - acc.oopMetCents;
225	  if (result.deltas.oopIncCents > oopRoomCents) {
226	    const excessCents = result.deltas.oopIncCents - oopRoomCents;
227	    result.memberResponsibilityCents -= excessCents; // member pays only up to the cap
228	    result.payableCents += excessCents; // the plan absorbs the rest
229	    result.deltas.oopIncCents = oopRoomCents; // OOP fills exactly to the max
230	    result.reasons = [...result.reasons, ReasonCode.OOP_MAX_REACHED];
231	    result.explanation += ` Your out-of-pocket maximum is reached, so the plan covers the remaining ${formatUsd(excessCents)}.`;
232	  }
233	
234	  return result;
235	}
