// app/src/services/claim.service.ts — orchestration: submit claim -> adjudicate -> persist.
//
// A SERVICE holds business logic / workflows; it depends on REPOSITORIES (which own the Db and
// encapsulate all data access), never on the raw connection. Layering: service → repositories → db.
// Every status change routes through the injected setStatus() chokepoint (status column + transition
// log in one write). The one-transaction-per-claim boundary is an injected withTransaction runner.

import { adjudicateLine } from "../domain/adjudication/adjudicator";
import type { ClaimStatus } from "../domain/entities/claim";
import {
  type LineOutcome,
  aggregateClaimStatus,
} from "../domain/state-machines/claim-state";
import type { AccumulatorRepository } from "../repositories/accumulator.repository";
import type { AdjudicationRepository } from "../repositories/adjudication.repository";
import type { ClaimRepository } from "../repositories/claim.repository";
import type { CoverageRuleRepository } from "../repositories/coverage-rule.repository";
import type { PolicyRepository } from "../repositories/policy.repository";
import type { SetStatus } from "./set-status";

export type ClaimServiceDeps = {
  claims: ClaimRepository;
  adjudications: AdjudicationRepository;
  accumulators: AccumulatorRepository;
  coverageRules: CoverageRuleRepository;
  policies: PolicyRepository;
  setStatus: SetStatus;
  withTransaction: <T>(fn: () => T) => T;
};

export type AdjudicateClaimInput = {
  memberId: string;
  serviceDate: string;
  provider?: string;
  diagnosisCode?: string;
  lineItems: {
    serviceCode: string;
    billedCents: number;
    units?: number;
    priorAuthPresent?: boolean;
  }[];
};

export type AdjudicateClaimResult = { claimId: string; status: ClaimStatus };

// An intake identity failure (4xx) — distinct from an adjudication decision (HTTP 200). Thrown when
// a claim cannot be resolved to a member's policy at all; the controller maps it to a 400 reject.
export class ClaimIntakeError extends Error {
  readonly field: string;
  readonly code: string;
  constructor(field: string, code: string, message: string) {
    super(message);
    this.name = "ClaimIntakeError";
    this.field = field;
    this.code = code;
  }
}

export function createClaimService(deps: ClaimServiceDeps) {
  function adjudicateClaim(input: AdjudicateClaimInput): AdjudicateClaimResult {
    return deps.withTransaction(() => {
      // Resolve the member's policy WITHOUT a date filter: an out-of-window date is a
      // POLICY_NOT_ACTIVE decision (the adjudicator's first gate), not an intake reject. Only a
      // member with no policy on file is unresolvable.
      const policy = deps.policies.findByMember(input.memberId);
      if (!policy) {
        throw new ClaimIntakeError(
          "memberId",
          "MEMBER_NOT_FOUND",
          `no policy on file for member ${input.memberId}`,
        );
      }
      const planYear = String(policy.planYear);
      const ruleByService = new Map(
        deps.coverageRules
          .findByPolicy(policy.id)
          .map((r) => [r.serviceCode, r]),
      );

      const claimId = deps.claims.insertClaim({
        memberId: input.memberId,
        policyId: policy.id,
        serviceDate: input.serviceDate,
        provider: input.provider ?? null,
        diagnosisCode: input.diagnosisCode ?? null,
      });
      deps.setStatus({
        claimId,
        target: { type: "CLAIM", status: "SUBMITTED" },
        fromStatus: null,
        actor: "SYSTEM",
        reason: "SUBMIT",
      });

      // Phase 1 — persist + submit every line (PENDING).
      const submitted = input.lineItems.map((li) => {
        const fingerprint = `${input.memberId}|${li.serviceCode}|${input.serviceDate}|${li.billedCents}`;
        const line = deps.claims.insertLine(claimId, {
          serviceCode: li.serviceCode,
          billedCents: li.billedCents,
          units: li.units,
          priorAuthPresent: li.priorAuthPresent,
          fingerprint,
        });
        deps.setStatus({
          claimId,
          target: { type: "LINE_ITEM", id: line.id, status: "PENDING" },
          fromStatus: null,
          actor: "SYSTEM",
          reason: "SUBMIT",
        });
        return { line, fingerprint };
      });

      // Phase 2 — adjudicate each line in order. One snapshot at claim start; deltas are applied to
      // this working copy between lines so a later line sees an earlier line's draw (determinism).
      const acc = deps.accumulators.snapshot(input.memberId, planYear);
      const touched = {
        deductible: false,
        oop: false,
        limits: new Set<string>(),
      };
      const outcomes: LineOutcome[] = [];

      for (const { line, fingerprint } of submitted) {
        const result = adjudicateLine({
          line: {
            id: line.id,
            claimId,
            serviceCode: line.serviceCode,
            billedCents: line.billedCents,
            units: line.units,
            priorAuthPresent: line.priorAuthPresent,
            status: "PENDING",
            fingerprint,
          },
          policy,
          rule: ruleByService.get(line.serviceCode),
          serviceDate: input.serviceDate,
          acc: {
            deductibleMetCents: acc.deductibleMetCents,
            oopMetCents: acc.oopMetCents,
            limitUsed: acc.limitUsedByService[line.serviceCode] ?? 0,
          },
          // Duplicate when another already-decided line shares this fingerprint — across a
          // prior claim or an earlier line in this same batch (see existsForFingerprint).
          alreadyAdjudicated: deps.adjudications.existsForFingerprint(
            fingerprint,
            line.id,
          ),
        });

        // adjudicateLine only ever decides APPROVED | DENIED (never PENDING/NEEDS_REVIEW)
        const newStatus = result.status as "APPROVED" | "DENIED";
        deps.adjudications.append({
          lineItemId: line.id,
          planYear,
          seq: 1, // first decision for this line; a dispute re-adjudication appends a higher seq
          status: newStatus,
          billedCents: line.billedCents,
          payableCents: result.payableCents,
          memberResponsibilityCents: result.memberResponsibilityCents,
          reasons: result.reasons,
          explanation: result.explanation,
          deltas: result.deltas,
        });
        deps.setStatus({
          claimId,
          target: { type: "LINE_ITEM", id: line.id, status: newStatus },
          fromStatus: "PENDING",
          actor: "SYSTEM",
          reason: "ADJUDICATED",
        });

        if (result.deltas.deductibleIncCents > 0) {
          acc.deductibleMetCents += result.deltas.deductibleIncCents;
          touched.deductible = true;
        }
        if (result.deltas.oopIncCents > 0) {
          acc.oopMetCents += result.deltas.oopIncCents;
          touched.oop = true;
        }
        if (result.deltas.limitInc > 0) {
          acc.limitUsedByService[line.serviceCode] =
            (acc.limitUsedByService[line.serviceCode] ?? 0) +
            result.deltas.limitInc;
          touched.limits.add(line.serviceCode);
        }

        outcomes.push({ status: newStatus, reasons: result.reasons });
      }

      // persist only the dimensions this claim actually touched (rows are created lazily)
      if (touched.deductible) {
        deps.accumulators.upsert({
          memberId: input.memberId,
          planYear,
          dimension: "DEDUCTIBLE",
          unit: "CENTS",
          usedCents: acc.deductibleMetCents,
          usedCount: 0,
        });
      }
      if (touched.oop) {
        deps.accumulators.upsert({
          memberId: input.memberId,
          planYear,
          dimension: "OOP",
          unit: "CENTS",
          usedCents: acc.oopMetCents,
          usedCount: 0,
        });
      }
      for (const service of touched.limits) {
        const isVisits = ruleByService.get(service)?.limit.unit === "visits";
        const used = acc.limitUsedByService[service] ?? 0;
        deps.accumulators.upsert({
          memberId: input.memberId,
          planYear,
          dimension: `LIMIT:${service}`,
          unit: isVisits ? "COUNT" : "CENTS",
          usedCents: isVisits ? 0 : used,
          usedCount: isVisits ? used : 0,
        });
      }

      const status = aggregateClaimStatus(outcomes);
      deps.setStatus({
        claimId,
        target: { type: "CLAIM", status },
        fromStatus: "SUBMITTED",
        actor: "SYSTEM",
        reason: "AGGREGATED",
      });
      return { claimId, status };
    });
  }

  return { ...deps, adjudicateClaim };
}

export type ClaimService = ReturnType<typeof createClaimService>;

// app/src/db/schema.ts — Drizzle table handles for typed queries.
//
// `schema.sql` (generated from docs/erd-physical.md) is the CANONICAL DDL — it creates the
// tables, CHECK constraints, composite FKs, partial indexes, and triggers that SQLite/Drizzle
// can't all express in TS. These Drizzle definitions MIRROR that DDL purely so repositories can
// build type-safe queries; they intentionally omit the CHECKs/triggers (the DB enforces those).
// snake_case DB columns ↔ camelCase TS properties (see the ERD's Drizzle/zod mapping table).

import { sql } from "drizzle-orm";
import { integer, real, sqliteTable, text } from "drizzle-orm/sqlite-core";
import type { ClaimStatus } from "../domain/entities/claim";
import type { LineItemStatus } from "../domain/entities/line-item";
import type { ReasonCode } from "../domain/reason-codes";

// All timestamps default to ISO-8601 UTC at the DB layer (metadata; never read by logic).
const nowDefault = sql`(strftime('%Y-%m-%dT%H:%M:%fZ','now'))`;

export const members = sqliteTable("members", {
  id: text("id").primaryKey(),
  name: text("name").notNull(), // PHI — stores AES-256-GCM ciphertext (see db/phi-crypto.ts)
  dob: text("dob").notNull(), // PHI — stores AES-256-GCM ciphertext
  createdAt: text("created_at").notNull().default(nowDefault),
});

export const policies = sqliteTable("policies", {
  id: text("id").primaryKey(),
  memberId: text("member_id")
    .notNull()
    .references(() => members.id),
  planYear: text("plan_year").notNull(),
  effectiveDate: text("effective_date").notNull(),
  terminationDate: text("termination_date").notNull(),
  deductibleCents: integer("deductible_cents").notNull(),
  oopMaxCents: integer("oop_max_cents").notNull(),
  createdAt: text("created_at").notNull().default(nowDefault),
});

export const coverageRules = sqliteTable("coverage_rules", {
  id: text("id").primaryKey(),
  policyId: text("policy_id")
    .notNull()
    .references(() => policies.id),
  serviceCode: text("service_code").notNull(),
  covered: integer("covered", { mode: "boolean" }).notNull(),
  excluded: integer("excluded", { mode: "boolean" }).notNull(),
  costShareType: text("cost_share_type", {
    enum: ["full_coverage", "copay", "coinsurance"],
  }).notNull(),
  copayCents: integer("copay_cents"), // non-null iff type=copay (CHECK in schema.sql)
  coinsuranceRate: real("coinsurance_rate"), // non-null iff type=coinsurance
  appliesDeductible: integer("applies_deductible", {
    mode: "boolean",
  }).notNull(),
  limitUnit: text("limit_unit", {
    enum: ["none", "dollars", "visits"],
  }).notNull(),
  limitAmountCents: integer("limit_amount_cents"), // non-null iff unit=dollars
  limitCount: integer("limit_count"), // non-null iff unit=visits
  requiresPriorAuth: integer("requires_prior_auth", {
    mode: "boolean",
  }).notNull(),
  createdAt: text("created_at").notNull().default(nowDefault),
});

export const claims = sqliteTable("claims", {
  id: text("id").primaryKey(),
  memberId: text("member_id")
    .notNull()
    .references(() => members.id),
  policyId: text("policy_id")
    .notNull()
    .references(() => policies.id),
  serviceDate: text("service_date").notNull(),
  provider: text("provider"), // PHI, nullable — AES-256-GCM ciphertext (see db/phi-crypto.ts)
  diagnosisCode: text("diagnosis_code"), // PHI, nullable — AES-256-GCM ciphertext
  status: text("status").$type<ClaimStatus>().notNull().default("SUBMITTED"),
  claimSeq: integer("claim_seq").notNull().default(0),
  createdAt: text("created_at").notNull().default(nowDefault),
  updatedAt: text("updated_at").notNull().default(nowDefault),
});

export const lineItems = sqliteTable("line_items", {
  id: text("id").primaryKey(),
  claimId: text("claim_id")
    .notNull()
    .references(() => claims.id),
  serviceCode: text("service_code").notNull(), // free text (unlisted → NO_COVERAGE at adj)
  billedCents: integer("billed_cents").notNull(),
  units: integer("units").notNull().default(1),
  priorAuthPresent: integer("prior_auth_present", { mode: "boolean" })
    .notNull()
    .default(true),
  status: text("status").$type<LineItemStatus>().notNull().default("PENDING"),
  fingerprint: text("fingerprint").notNull(),
  createdAt: text("created_at").notNull().default(nowDefault),
  updatedAt: text("updated_at").notNull().default(nowDefault),
});

export const adjudications = sqliteTable("adjudications", {
  id: text("id").primaryKey(),
  lineItemId: text("line_item_id")
    .notNull()
    .references(() => lineItems.id),
  planYear: text("plan_year").notNull(),
  seq: integer("seq").notNull(), // per-line clock; current = MAX(seq)
  status: text("status").$type<"APPROVED" | "DENIED">().notNull(),
  billedCents: integer("billed_cents").notNull(), // snapshot at decision time
  payableCents: integer("payable_cents").notNull(),
  memberResponsibilityCents: integer("member_responsibility_cents").notNull(),
  reasonsJson: text("reasons_json", { mode: "json" })
    .$type<ReasonCode[]>()
    .notNull(),
  explanation: text("explanation").notNull(),
  deltaDeductibleIncCents: integer("delta_deductible_inc_cents")
    .notNull()
    .default(0),
  deltaOopIncCents: integer("delta_oop_inc_cents").notNull().default(0),
  deltaLimitInc: integer("delta_limit_inc").notNull().default(0),
  createdAt: text("created_at").notNull().default(nowDefault),
});

export const accumulators = sqliteTable("accumulators", {
  id: text("id").primaryKey(),
  memberId: text("member_id")
    .notNull()
    .references(() => members.id),
  planYear: text("plan_year").notNull(),
  dimension: text("dimension").notNull(), // DEDUCTIBLE | OOP | LIMIT:<service_code>
  unit: text("unit", { enum: ["CENTS", "COUNT"] }).notNull(),
  usedCents: integer("used_cents").notNull().default(0),
  usedCount: integer("used_count").notNull().default(0),
  updatedAt: text("updated_at").notNull().default(nowDefault),
});

export const disputes = sqliteTable("disputes", {
  id: text("id").primaryKey(),
  lineItemId: text("line_item_id")
    .notNull()
    .references(() => lineItems.id),
  // original/resolved adjudication ids use COMPOSITE FKs (id,line_item_id) — enforced in schema.sql.
  originalAdjudicationId: text("original_adjudication_id").notNull(),
  resolvedAdjudicationId: text("resolved_adjudication_id"), // null while OPEN
  reason: text("reason").notNull(),
  correctedPriorAuthPresent: integer("corrected_prior_auth_present", {
    mode: "boolean",
  }),
  correctedServiceCode: text("corrected_service_code"),
  correctedBilledCents: integer("corrected_billed_cents"),
  correctedUnits: integer("corrected_units"),
  outcome: text("outcome", {
    enum: ["UPHELD", "OVERTURNED", "PARTIALLY_OVERTURNED", "MODIFIED"],
  }), // null while OPEN
  state: text("state", { enum: ["OPEN", "RESOLVED"] })
    .notNull()
    .default("OPEN"),
  openedAt: text("opened_at").notNull().default(nowDefault),
  resolvedAt: text("resolved_at"), // null while OPEN
});

export const statusTransitions = sqliteTable("status_transitions", {
  id: text("id").primaryKey(),
  entityType: text("entity_type", { enum: ["CLAIM", "LINE_ITEM"] }).notNull(),
  claimId: text("claim_id")
    .notNull()
    .references(() => claims.id), // owning claim aggregate; always set
  lineItemId: text("line_item_id").references(() => lineItems.id), // set iff LINE_ITEM
  fromStatus: text("from_status"), // null on create
  toStatus: text("to_status").notNull(),
  actor: text("actor", { enum: ["SYSTEM", "MEMBER"] }).notNull(),
  reason: text("reason", {
    enum: ["SUBMIT", "ADJUDICATED", "AGGREGATED", "DISPUTE_REOPEN"],
  }).notNull(),
  seq: integer("seq").notNull(), // claim-aggregate logical clock
  createdAt: text("created_at").notNull().default(nowDefault),
});

